func:
msg.payload = {
    status: 'healthy',
    version: process.env.RUNTIME_VERSION || 'v3.4',
    uptime: process.uptime(),
    timestamp: new Date().toISOString()
};
return msg;

const tid = msg.trace_id || msg._msgid || ('m' + Date.now());
msg.trace_id = tid;

const p = Array.isArray(msg.payload)
    ? (msg.payload[0] != null ? msg.payload[0] : {})
    : (msg.payload != null ? msg.payload : {});

// 入库拒收校验 (010-nodered-core.mdc 第4条)
if (!p.order_id || p.weight == null || p.weight <= 0 || !p.location) {
    msg.statusCode = 400;
    msg.payload = {
        error: 'INVALID',
        tid: tid,
        details: 'order_id/weight(>0)/location required'
    };
    return msg;
}

// 安全模式检查
const safeMode = global.get('safe_mode');
if (safeMode) {
    msg.statusCode = 503;
    msg.payload = {
        error: 'SAFE_MODE',
        tid: tid,
        details: 'System in safe mode, order rejected'
    };
    return msg;
}

msg._validated = {
    order_id: p.order_id,
    weight: p.weight,
    location: p.location,
    brand: p.brand || 'generic',
    zone_id: p.zone_id || null,
    priority: p.priority || 0
};

return msg;

const v = msg._validated;

// 分配 zone_token (区域锁)
const zoneToken = v.zone_id ? ('zt_' + Date.now() + '_' + Math.random().toString(36).substr(2, 8)) : null;

msg.payload = {
    order_no: v.order_id,
    status: 'CREATED',
    weight: v.weight,
    location: v.location,
    zone_id: v.zone_id,
    zone_token: zoneToken,
    brand: v.brand,
    priority: v.priority,
    created_at: new Date().toISOString(),
    version: 1
};

return msg;

// Outbox 写入: audit_log + orders (010-nodered-core.mdc 第3条)
const order = msg.payload;

// 写入 audit_log
msg.audit_event = {
    event: 'ORDER_CREATED',
    order_no: order.order_no,
    status: 'CREATED',
    timestamp: new Date().toISOString(),
    trace_id: msg.trace_id
};

return msg;

const order = msg.payload;

// 品牌路由策略 (v3.4 策略模式)
const brand = order.brand || 'generic';

// 电量检查 (模拟，生产环境从 robot_status 表读取)
// 电量 < 20% 限制短单

msg.next_status = 'DISPATCHED';
msg.current_status = 'CREATED';

// 状态机校验 (050-state-machine.mdc)
const ok = {
    CREATED: ['DISPATCHED','CANCELLED'],
    DISPATCHED: ['EXECUTING','SUSPENDED','RECALLING','CANCELLED'],
    EXECUTING: ['COMPLETED','DIFF_SUSPENDED','SUSPENDED'],
    COMPLETED: ['SAP_CONFIRMED','SAP_PENDING'],
    SUSPENDED: ['DISPATCHED','MANUAL_HANDLED','CANCELLED','DEGRADED'],
    DIFF_SUSPENDED: ['COMPLETED','MANUAL_HANDLED','SUSPENDED'],
    RECALLING: ['CANCELLED'],
    SAP_PENDING: ['SAP_CONFIRMED','SUSPENDED']
};

const A = msg.current_status;
const B = msg.next_status;

if (A && B && ok[A] && ok[A].indexOf(B) === -1) {
    msg.statusCode = 409;
    msg.payload = { error: 'BAD_STATE', A: A, B: B, tid: msg.trace_id };
    return msg;
}

msg.payload.status = 'DISPATCHED';
msg.payload.updated_at = new Date().toISOString();

return msg;

// 由 Watchdog 或主管手动触发
global.set('safe_mode', true);

msg.payload = {
    status: 'SAFE_MODE_ENTERED',
    timestamp: new Date().toISOString()
};

return msg;

global.set('safe_mode', false);

msg.payload = {
    status: 'SAFE_MODE_EXITED',
    timestamp: new Date().toISOString()
};

return msg;

// 从 Redis 读取系统安全模式标志
// Watchdog 写入 system:safe_mode 时自动进入安全模式
// 生产环境: 使用 contextStorage.redis 读取

// 模拟: 检查 context (Redis context 启用后自动同步)
const redisSafeMode = context.env.get('REDIS_SAFE_MODE');

if (redisSafeMode) {
    global.set('safe_mode', true);
    node.warn('[WATCHDOG] 安全模式已由 Watchdog 激活: ' + redisSafeMode);
} else {
    // 不自动解除，需人工 /api/restore-mode
}

return msg;

// 返回当前区域锁状态
// 生产环境从 SQLite zone_lock 表读取

msg.payload = {
    zones: global.get('zone_locks') || {},
    timestamp: new Date().toISOString()
};

return msg;

// 查询所有 PENDING outbox 事件 (retry_count < 5)
const Database = require('sqlite3');
const dbPath = context.env.get('DB_PATH') || '/data/robot_platform.db';

const db = new Database(dbPath);

try {
    const rows = db.prepare(
        `SELECT id, order_id, event_type, payload, retry_count, created_at
         FROM outbox_events
         WHERE status = 'PENDING' AND retry_count < 5
         ORDER BY created_at ASC
         LIMIT 20`
    ).all();

    if (rows.length === 0) {
        msg.payload = [];
        msg._count = 0;
        return msg;
    }

    // Parse payload JSON for each row
    const events = rows.map(row => ({
        ...row,
        payload: (() => { try { return JSON.parse(row.payload); } catch(e) { return {}; } })()
    }));

    msg.payload = events;
    msg._count = events.length;
    msg._index = 0;
    node.status({fill:'blue',shape:'dot',text:'${events.length} pending'});
    return msg;
} finally {
    db.close();
}

// 根据 event_type 构建 SAP Bridge 请求
const event = msg.payload;

if (!event || !event.id) {
    return null;
}

msg._outbox_id = event.id;
msg._order_id = event.order_id;
msg._event_type = event.event_type;
msg._retry_count = event.retry_count || 0;

// 根据事件类型路由
switch (event.event_type) {
    case 'ORDER_CONFIRM':
    case 'WAREHOUSE_TASK_CONFIRM':
        msg.url = 'http://sap-bridge:8000/api/v1/sap/tasks/' + encodeURIComponent(event.order_id) + '/confirm?warehouse=WM01';
        msg.method = 'POST';
        break;

    case 'ORDER_CANCEL':
        msg.url = 'http://sap-bridge:8000/api/v1/sap/tasks/' + encodeURIComponent(event.order_id) + '/cancel?warehouse=WM01';
        msg.method = 'POST';
        break;

    case 'INVENTORY_SYNC':
        msg.url = 'http://sap-bridge:8000/api/v1/inventory/sync?warehouse=WM01';
        msg.method = 'POST';
        break;

    case 'SAP_HEALTH_CHECK':
        msg.url = 'http://sap-bridge:8000/api/v1/sap/health';
        msg.method = 'GET';
        break;

    default:
        // Unknown event type - try posting to SAP Bridge order API
        msg.url = 'http://sap-bridge:8000/api/v1/orders';
        msg.method = 'POST';
        msg.payload = event.payload || {};
        break;
}

node.status({fill:'yellow',shape:'dot',text:'processing #' + event.id});
return msg;

// 根据 HTTP 响应更新 outbox_events 状态
const Database = require('sqlite3');
const dbPath = context.env.get('DB_PATH') || '/data/robot_platform.db';
const db = new Database(dbPath);

const outboxId = msg._outbox_id;
const orderId = msg._order_id;
const statusCode = msg.statusCode || 500;

try {
    if (statusCode >= 200 && statusCode < 300) {
        // ✅ 成功
        db.prepare(
            `UPDATE outbox_events SET status = 'SENT', retry_count = retry_count + 1
             WHERE id = ?`
        ).run(outboxId);

        msg._success = true;
        node.status({fill:'green',shape:'dot',text:'sent #' + outboxId});
        node.warn('[OUTBOX] Sent event #' + outboxId + ' (order=' + orderId + ')');
    } else {
        // ❌ 失败：增加重试次数
        const result = db.prepare(
            `UPDATE outbox_events SET retry_count = retry_count + 1
             WHERE id = ? AND status = 'PENDING'`
        ).run(outboxId);

        // 读取最新的 retry_count
        const row = db.prepare(
            `SELECT retry_count, status FROM outbox_events WHERE id = ?`
        ).get(outboxId);

        msg._retry_count = row ? row.retry_count : (msg._retry_count + 1);
        msg._success = false;
        msg._status_code = statusCode;

        if (row && row.retry_count >= 5) {
            msg._deadletter = true;
            node.status({fill:'red',shape:'dot',text:'deadletter #' + outboxId});
            node.warn('[OUTBOX] Event #' + outboxId + ' deadlettered after 5 retries');
        } else {
            node.status({fill:'yellow',shape:'dot',text:'retry #' + (row ? row.retry_count : '?')});
            node.warn('[OUTBOX] Event #' + outboxId + ' failed (HTTP ' + statusCode + '), will retry');
        }
    }

    return msg;
} finally {
    db.close();
}

// 将失败事件写入 dead_letter_queue
const Database = require('sqlite3');
const dbPath = context.env.get('DB_PATH') || '/data/robot_platform.db';
const db = new Database(dbPath);

try {
    db.prepare(
        `INSERT INTO dead_letter_queue (original_id, error_type, error_message, payload, status)
         VALUES (?, ?, ?, ?, 'UNRESOLVED')`
    ).run(
        msg._outbox_id || 0,
        'OUTBOX_RETRY_EXCEEDED',
        'Outbox event failed after ' + (msg._retry_count || 5) + ' retries (HTTP ' + (msg._status_code || 'unknown') + ')',
        JSON.stringify({
            order_id: msg._order_id,
            event_type: msg._event_type,
            outbox_id: msg._outbox_id
        })
    );

    // 更新出库事件状态为 FAILED
    db.prepare(
        `UPDATE outbox_events SET status = 'FAILED' WHERE id = ?`
    ).run(msg._outbox_id);

    node.status({fill:'red',shape:'dot',text:'DLQ #' + msg._outbox_id});
    node.warn('[OUTBOX] Event #' + msg._outbox_id + ' sent to dead letter queue');
    return msg;
} finally {
    db.close();
}

// 当 HTTP 请求本身失败（网络错误、超时）时的兜底处理
msg._success = false;

// 增加重试计数
const Database = require('sqlite3');
const dbPath = context.env.get('DB_PATH') || '/data/robot_platform.db';
const db = new Database(dbPath);

try {
    db.prepare(
        `UPDATE outbox_events SET retry_count = retry_count + 1 WHERE id = ?`
    ).run(msg._outbox_id);

    const row = db.prepare(
        `SELECT retry_count FROM outbox_events WHERE id = ?`
    ).get(msg._outbox_id);

    msg._retry_count = row ? row.retry_count : 5;
    msg._deadletter = (msg._retry_count >= 5);
    msg._status_code = 0;

    if (msg._deadletter) {
        node.warn('[OUTBOX] Event #' + msg._outbox_id + ' deadlettered (HTTP error)');
    }
    return msg;
} finally {
    db.close();
}
